//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageelbv2import("testing"sdkacctest"github.com/hashicorp/terraform-plugin-testing/helper/acctest")funcTestValidName(t*testing.T){t.Parallel()validNames:=[]string{"tf-test-elb",}for_,s:=rangevalidNames{_,errors:=validName(s,"name")iflen(errors)>0{t.Fatalf("%qshouldbeavalidELBname:%v",s,errors)}}invalidNames:=[]string{"tf.test.elb.1","tf-test-elb-tf-test-elb-tf-test-elb","-tf-test-elb","tf-test-elb-","internal-tf-test-elb",}for_,s:=rangeinvalidNames{_,errors:=validName(s,"name")iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidELBname:%v",s,errors)}}}funcTestValidNamePrefix(t*testing.T){t.Parallel()validNamePrefixes:=[]string{"test-",}for_,s:=rangevalidNamePrefixes{_,errors:=validNamePrefix(s,"name_prefix")iflen(errors)>0{t.Fatalf("%qshouldbeavalidELBnameprefix:%v",s,errors)}}invalidNamePrefixes:=[]string{"tf.test.elb.","tf-test","-test","internal-",}for_,s:=rangeinvalidNamePrefixes{_,errors:=validNamePrefix(s,"name_prefix")iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidELBnameprefix:%v",s,errors)}}}funcTestValidTargetGroupName(t*testing.T){t.Parallel()cases:=[]struct{ValuestringErrCountint}{{Value:"tf.test.elb.target.1",ErrCount:1,},{Value:"-tf-test-target",ErrCount:1,},{Value:"tf-test-target-",ErrCount:1,},{Value:sdkacctest.RandStringFromCharSet(33,sdkacctest.CharSetAlpha),ErrCount:1,},}for_,tc:=rangecases{_,errors:=validTargetGroupName(tc.Value,"aws_lb_target_group")iflen(errors)!=tc.ErrCount{t.Fatalf("ExpectedtheAWSLBTargetGroupNametotriggeravalidationerrorfor%q",tc.Value)}}}funcTestValidTargetGroupNamePrefix(t*testing.T){t.Parallel()cases:=[]struct{ValuestringErrCountint}{{Value:"tf.lb",ErrCount:1,},{Value:"-tf-lb",ErrCount:1,},{Value:sdkacctest.RandStringFromCharSet(32,sdkacctest.CharSetAlpha),ErrCount:1,},}for_,tc:=rangecases{_,errors:=validTargetGroupNamePrefix(tc.Value,"aws_lb_target_group")iflen(errors)!=tc.ErrCount{t.Fatalf("ExpectedtheAWSLBTargetGroupNametotriggeravalidationerrorfor%q",tc.Value)}}}